  ('retired-d0d1b9a2-moex-00275', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，X1年12月2日中央政府撥款，補助甲縣政府B 機關辦理X2年度公車搭乘人數擴大計畫，尚未納編地方預算。嗣甲縣政府B機關將補助收入列 入X2年度地方預算，並經縣議會審查通過，甲縣政府B機關於X2年1月1日認列補助收入之 分錄為何？', '["借：繳付公庫數，貸：補助收入", "借：預收其他政府款，貸：補助收入", "借：公庫撥入數，貸：補助收入", "借：預收款，貸：補助收入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "40dfdafc3673", "answer_pdf_sha1": "48bd8f791b74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
